import json
import boto3
from datetime import datetime
from typing import Dict, Any, Optional, List

sns_client = boto3.client('sns')

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    """
    Lambda function to publish messages to SNS topics based on notification type.
    
    Event structure:
    {
        "topic_arn": "arn:aws:sns:region:account:topic-name",
        "message": "Message content or object",
        "subject": "Optional subject",
        "notification_type": "simple|structured|batch|filtered",
        "message_attributes": {},
        "phone_number": "Optional for SMS",
        "message_structure": "json|string"
    }
    """
    try:
        notification_type = event.get('notification_type', 'simple')
        
        if notification_type == 'simple':
            result = publish_simple_notification(event)
        elif notification_type == 'structured':
            result = publish_structured_notification(event)
        elif notification_type == 'batch':
            result = publish_batch_notifications(event)
        elif notification_type == 'filtered':
            result = publish_filtered_notification(event)
        elif notification_type == 'sms':
            result = publish_sms_notification(event)
        elif notification_type == 'mobile':
            result = publish_mobile_notification(event)
        else:
            raise ValueError(f"Unsupported notification type: {notification_type}")
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'success': True,
                'result': result,
                'timestamp': datetime.utcnow().isoformat()
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'success': False,
                'error': str(e),
                'timestamp': datetime.utcnow().isoformat()
            })
        }


def publish_simple_notification(event: Dict[str, Any]) -> Dict[str, Any]:
    """Publish a simple text message to SNS topic."""
    topic_arn = event['topic_arn']
    message = event['message']
    subject = event.get('subject', '')
    
    params = {
        'TopicArn': topic_arn,
        'Message': message if isinstance(message, str) else json.dumps(message)
    }
    
    if subject:
        params['Subject'] = subject
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'notification_type': 'simple',
        'topic_arn': topic_arn
    }


def publish_structured_notification(event: Dict[str, Any]) -> Dict[str, Any]:
    """Publish a structured message with different formats for different protocols."""
    topic_arn = event['topic_arn']
    message_content = event['message']
    subject = event.get('subject', '')
    
    # Create message structure for different protocols
    if isinstance(message_content, dict):
        default_message = message_content.get('default', json.dumps(message_content))
        
        message_structure = {
            'default': default_message,
            'email': message_content.get('email', default_message),
            'sms': message_content.get('sms', default_message[:160]),
            'sqs': message_content.get('sqs', json.dumps(message_content)),
            'lambda': message_content.get('lambda', json.dumps(message_content)),
            'http': message_content.get('http', json.dumps(message_content)),
            'https': message_content.get('https', json.dumps(message_content))
        }
    else:
        message_structure = {
            'default': str(message_content)
        }
    
    params = {
        'TopicArn': topic_arn,
        'Message': json.dumps(message_structure),
        'MessageStructure': 'json'
    }
    
    if subject:
        params['Subject'] = subject
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'notification_type': 'structured',
        'topic_arn': topic_arn,
        'protocols': list(message_structure.keys())
    }


def publish_batch_notifications(event: Dict[str, Any]) -> Dict[str, Any]:
    """Publish multiple messages in batch."""
    messages = event.get('messages', [])
    results = []
    errors = []
    
    for idx, msg in enumerate(messages):
        try:
            topic_arn = msg.get('topic_arn') or event.get('topic_arn')
            message = msg['message']
            subject = msg.get('subject', '')
            message_attributes = msg.get('message_attributes', {})
            
            params = {
                'TopicArn': topic_arn,
                'Message': message if isinstance(message, str) else json.dumps(message)
            }
            
            if subject:
                params['Subject'] = subject
            
            if message_attributes:
                params['MessageAttributes'] = format_message_attributes(message_attributes)
            
            response = sns_client.publish(**params)
            
            results.append({
                'index': idx,
                'message_id': response['MessageId'],
                'success': True
            })
            
        except Exception as e:
            errors.append({
                'index': idx,
                'error': str(e),
                'success': False
            })
    
    return {
        'notification_type': 'batch',
        'total': len(messages),
        'successful': len(results),
        'failed': len(errors),
        'results': results,
        'errors': errors
    }


def publish_filtered_notification(event: Dict[str, Any]) -> Dict[str, Any]:
    """Publish message with filter attributes for subscription filtering."""
    topic_arn = event['topic_arn']
    message = event['message']
    subject = event.get('subject', '')
