def publish_sms_notification(event: Dict[str, Any]) -> Dict[str, Any]:
    """Publish SMS notification to a phone number."""
    phone_number = event['phone_number']
    message = event['message']
    message_attributes = event.get('message_attributes', {})
    
    params = {
        'PhoneNumber': phone_number,
        'Message': message if isinstance(message, str) else json.dumps(message)
    }
    
    # Add SMS-specific attributes
    sms_attributes = {
        'AWS.SNS.SMS.SenderID': {'DataType': 'String', 'StringValue': event.get('sender_id', 'AWS')},
        'AWS.SNS.SMS.SMSType': {'DataType': 'String', 'StringValue': event.get('sms_type', 'Transactional')}
    }
    
    if message_attributes:
        sms_attributes.update(format_message_attributes(message_attributes))
    
    params['MessageAttributes'] = sms_attributes
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'notification_type': 'sms',
        'phone_number': phone_number
    }


def publish_mobile_notification(event: Dict[str, Any]) -> Dict[str, Any]:
    """Publish mobile push notification."""
    target_arn = event.get('target_arn') or event.get('topic_arn')
    message_content = event['message']
    
    # Create platform-specific message
    if isinstance(message_content, dict):
        gcm_message = message_content.get('GCM', {})
        apns_message = message_content.get('APNS', {})
        
        message_structure = {}
        
        if gcm_message:
            message_structure['GCM'] = json.dumps({
                'data': gcm_message
            })
        
        if apns_message:
            message_structure['APNS'] = json.dumps({
                'aps': apns_message
            })
        
        message_structure['default'] = message_content.get('default', 'New notification')
        
        params = {
            'TargetArn': target_arn,
            'Message': json.dumps(message_structure),
            'MessageStructure': 'json'
        }
    else:
        params = {
            'TargetArn': target_arn,
            'Message': str(message_content)
        }
    
    subject = event.get('subject')
    if subject:
        params['Subject'] = subject
    
    response = sns_client.publish(**params)
    
    return {
        'message_id': response['MessageId'],
        'notification_type': 'mobile',
        'target_arn': target_arn
    }


def format_message_attributes(attributes: Dict[str, Any]) -> Dict[str, Dict[str, str]]:
    """Format message attributes for SNS."""
    formatted_attrs = {}
    
    for key, value in attributes.items():
        if isinstance(value, dict) and 'DataType' in value:
            formatted_attrs[key] = value
        else:
            # Auto-detect data type
            if isinstance(value, str):
                formatted_attrs[key] = {
                    'DataType': 'String',
                    'StringValue': value
                }
            elif isinstance(value, (int, float)):
                formatted_attrs[key] = {
                    'DataType': 'Number',
                    'StringValue': str(value)
                }
            elif isinstance(value, list):
                formatted_attrs[key] = {
                    'DataType': 'String.Array',
                    'StringValue': json.dumps(value)
                }
            else:
                formatted_attrs[key] = {
                    'DataType': 'String',
                    'StringValue': json.dumps(value)
                }
    
    return formatted_attrs